const GMAIL_CLIENT_ID = "230761387106-a6vbitsireua1lq9nig4vp6b6v31hg3d.apps.googleusercontent.com";
const GMAIL_REDIRECT = "https://sales-crm-drab.vercel.app/auth/gmail/callback";
const GMAIL_SCOPES = "https://www.googleapis.com/auth/gmail.send https://www.googleapis.com/auth/gmail.readonly https://www.googleapis.com/auth/userinfo.email";

const gmail = {
  getAuthUrl() {
    const params = new URLSearchParams({
      client_id: GMAIL_CLIENT_ID,
      redirect_uri: GMAIL_REDIRECT,
      response_type: "code",
      scope: GMAIL_SCOPES,
      access_type: "offline",
      prompt: "consent",
    });
    return `https://accounts.google.com/o/oauth2/v2/auth?${params}`;
  },
  async exchangeCode(code) {
    const r = await fetch("https://oauth2.googleapis.com/token", {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        code,
        client_id: GMAIL_CLIENT_ID,
        client_secret: import.meta.env.VITE_GMAIL_CLIENT_SECRET,
        redirect_uri: GMAIL_REDIRECT,
        grant_type: "authorization_code",
      }),
    });
    return r.json();
  },
  async refreshToken(refreshToken) {
    const r = await fetch("https://oauth2.googleapis.com/token", {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        refresh_token: refreshToken,
        client_id: GMAIL_CLIENT_ID,
        client_secret: import.meta.env.VITE_GMAIL_CLIENT_SECRET,
        grant_type: "refresh_token",
      }),
    });
    return r.json();
  },
  async getProfile(accessToken) {
    const r = await fetch("https://www.googleapis.com/oauth2/v2/userinfo", {
      headers: { Authorization: `Bearer ${accessToken}` },
    });
    return r.json();
  },
  async sendEmail(accessToken, { to, subject, body, fromName, fromEmail }) {
    const msg = [
      `From: ${fromName} <${fromEmail}>`,
      `To: ${to}`,
      `Subject: ${subject}`,
      `Content-Type: text/plain; charset=utf-8`,
      `MIME-Version: 1.0`,
      "",
      body,
    ].join("\r\n");
    const encoded = btoa(unescape(encodeURIComponent(msg)))
      .replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
    const r = await fetch("https://gmail.googleapis.com/gmail/v1/users/me/messages/send", {
      method: "POST",
      headers: { Authorization: `Bearer ${accessToken}`, "Content-Type": "application/json" },
      body: JSON.stringify({ raw: encoded }),
    });
    return r.json();
  },
  async listMessages(accessToken, query = "", maxResults = 10) {
    const params = new URLSearchParams({ q: query, maxResults });
    const r = await fetch(`https://gmail.googleapis.com/gmail/v1/users/me/messages?${params}`, {
      headers: { Authorization: `Bearer ${accessToken}` },
    });
    return r.json();
  },
  async getMessage(accessToken, messageId) {
    const r = await fetch(`https://gmail.googleapis.com/gmail/v1/users/me/messages/${messageId}?format=full`, {
      headers: { Authorization: `Bearer ${accessToken}` },
    });
    return r.json();
  },
  saveToken(token) {
    if (typeof window === "undefined") return;
    localStorage.setItem("gmail_token", JSON.stringify(token));
  },
  loadToken() {
    if (typeof window === "undefined") return null;
    try { return JSON.parse(localStorage.getItem("gmail_token")); } catch { return null; }
  },
  clearToken() {
    if (typeof window === "undefined") return;
    localStorage.removeItem("gmail_token");
  },
  isExpired(token) {
    if (!token?.expires_at) return true;
    return Date.now() >= token.expires_at - 60000;
  },
};
