// APPLY FILTERS TO PROSPECTS 
function applyProspectFilters(prospects,filters,search){
 const now=new Date();
 const today=new Date();today.setHours(0,0,0,0);
 const tomorrow=new Date(today);tomorrow.setDate(today.getDate()+1);
 const weekEnd=new Date(today);weekEnd.setDate(today.getDate()+7);

 let list=[...prospects];

 // Search
 if(search)list=list.filter(p=>{const cs=(p.contacts||[{name:p.contact,email:p.email}]).map(c=>c.name+' '+c.email).join(' ');return(p.company+' '+cs).toLowerCase().includes(search.toLowerCase());});

 // Owner
 if(filters.owner)list=list.filter(p=>p.owner===filters.owner);

 // Status
 if(filters.status)list=list.filter(p=>p.status===filters.status);

 // Touch count
 if(filters.touchMin){const min=Number(filters.touchMin);list=list.filter(p=>(p.touches||[]).length>=min);}

 // Touch type
 if(filters.touchType)list=list.filter(p=>(p.touches||[]).some(t=>t.type===filters.touchType));

 // Email opened/replied
 if(filters.hasOpened==="yes")list=list.filter(p=>(p.touches||[]).some(t=>t.opened));
 if(filters.hasOpened==="no")list=list.filter(p=>!(p.touches||[]).some(t=>t.opened));
 if(filters.hasReplied==="yes")list=list.filter(p=>(p.touches||[]).some(t=>t.replied));
 if(filters.hasReplied==="no")list=list.filter(p=>!(p.touches||[]).some(t=>t.replied));

 // Contact info
  if(filters.hasEmail==="yes")list=list.filter(p=>(p.contacts||[{email:p.email}]).some(c=>c.email&&c.email.trim()));
  if(filters.hasEmail==="no")list=list.filter(p=>!(p.contacts||[{email:p.email}]).some(c=>c.email&&c.email.trim()));
 if(filters.hasLinkedIn==="yes")list=list.filter(p=>p.linkedin&&p.linkedin.trim());
 if(filters.hasLinkedIn==="no")list=list.filter(p=>!p.linkedin||!p.linkedin.trim());
 if(filters.hasSecondary==="yes")list=list.filter(p=>(p.contacts||[]).length>1);
 if(filters.hasSecondary==="no")list=list.filter(p=>(p.contacts||[]).length<=1);

 // Completeness
 if(filters.completeness){
   const primaryContact=(p)=>(p.contacts&&p.contacts.length>0)?p.contacts[0]:{name:p.contact,email:p.email,title:p.title};
   if(filters.completeness==="no_contact")list=list.filter(p=>!primaryContact(p).name||!primaryContact(p).name.trim());
   if(filters.completeness==="no_email")list=list.filter(p=>!primaryContact(p).email||!primaryContact(p).email.trim());
   if(filters.completeness==="no_title")list=list.filter(p=>!primaryContact(p).title||!primaryContact(p).title.trim());
   if(filters.completeness==="incomplete")list=list.filter(p=>{
     const c=primaryContact(p);
     return !c.name||!c.name.trim()||!c.email||!c.email.trim()||!c.title||!c.title.trim();
   });
   if(filters.completeness==="complete")list=list.filter(p=>{
     const c=primaryContact(p);
     return c.name&&c.name.trim()&&c.email&&c.email.trim()&&c.title&&c.title.trim();
   });
 }

 // Sequence
 if(filters.hasSequence==="yes")list=list.filter(p=>(p.sequences||[]).length>0);
 if(filters.hasSequence==="no")list=list.filter(p=>!(p.sequences||[]).length);
 if(filters.sequenceComplete==="yes")list=list.filter(p=>{const s=p.sequences||[];const t=(p.touches||[]).filter(x=>x.type==="Email").length;return s.length>0&&t>=s.length;});
 if(filters.sequenceComplete==="no")list=list.filter(p=>{const s=p.sequences||[];const t=(p.touches||[]).filter(x=>x.type==="Email").length;return s.length>0&&t<s.length;});
 if(filters.sequenceComplete==="none")list=list.filter(p=>{const s=p.sequences||[];const t=(p.touches||[]).filter(x=>x.type==="Email").length;return s.length>0&&t===0;});

 // Follow-up range
 if(filters.followUpRange==="overdue")list=list.filter(p=>p.nextFollowUp&&new Date(p.nextFollowUp)<today);
 if(filters.followUpRange==="today")list=list.filter(p=>p.nextFollowUp&&new Date(p.nextFollowUp)>=today&&new Date(p.nextFollowUp)<tomorrow);
 if(filters.followUpRange==="week")list=list.filter(p=>p.nextFollowUp&&new Date(p.nextFollowUp)>=today&&new Date(p.nextFollowUp)<=weekEnd);
 if(filters.followUpRange==="none")list=list.filter(p=>!p.nextFollowUp);

 // Last activity range
 const dAgo=days=>new Date(now.getTime()-days*24*60*60*1000);
 if(filters.lastActivityRange==="today")list=list.filter(p=>new Date(p.lastActivity)>=today);
 if(filters.lastActivityRange==="week")list=list.filter(p=>new Date(p.lastActivity)>=dAgo(7));
 if(filters.lastActivityRange==="month")list=list.filter(p=>new Date(p.lastActivity)>=dAgo(30));
 if(filters.lastActivityRange==="14+")list=list.filter(p=>new Date(p.lastActivity)<dAgo(14));
 if(filters.lastActivityRange==="30+")list=list.filter(p=>new Date(p.lastActivity)<dAgo(30));
 if(filters.lastActivityRange==="60+")list=list.filter(p=>new Date(p.lastActivity)<dAgo(60));
 if(filters.lastActivityRange==="90+")list=list.filter(p=>new Date(p.lastActivity)<dAgo(90));

 // Date added
 if(filters.addedRange==="today")list=list.filter(p=>new Date(p.createdAt)>=today);
 if(filters.addedRange==="week")list=list.filter(p=>new Date(p.createdAt)>=dAgo(7));
 if(filters.addedRange==="month")list=list.filter(p=>new Date(p.createdAt)>=dAgo(30));
 if(filters.addedRange==="30")list=list.filter(p=>new Date(p.createdAt)>=dAgo(30));
 if(filters.addedRange==="90")list=list.filter(p=>new Date(p.createdAt)>=dAgo(90));

 // Quick flags
 if(filters.neverContacted)list=list.filter(p=>(p.touches||[]).length===0);
 if(filters.overdueFU)list=list.filter(p=>p.nextFollowUp&&new Date(p.nextFollowUp)<today);
 if(filters.noFUSet)list=list.filter(p=>!p.nextFollowUp);
 if(filters.coldProspect)list=list.filter(p=>{
 const hasEmail=(p.touches||[]).some(t=>t.type==="Email");
 const hasReply=(p.touches||[]).some(t=>t.replied);
 const lastAct=new Date(p.lastActivity);
 return hasEmail&&!hasReply&&(now-lastAct)>14*24*60*60*1000;
 });

 // Sort
 list.sort((a,b)=>{
 switch(filters.sort){
 case "company_asc":return(a.company||"").localeCompare(b.company||"");
 case "company_desc":return(b.company||"").localeCompare(a.company||"");
 case "contact_asc":return(a.contact||"").localeCompare(b.contact||"");
 case "contact_desc":return(b.contact||"").localeCompare(a.contact||"");
 case "lastActivity_desc":return new Date(b.lastActivity||0)-new Date(a.lastActivity||0);
 case "lastActivity_asc":return new Date(a.lastActivity||0)-new Date(b.lastActivity||0);
 case "createdAt_desc":return new Date(b.createdAt||0)-new Date(a.createdAt||0);
 case "createdAt_asc":return new Date(a.createdAt||0)-new Date(b.createdAt||0);
 case "touches_desc":return(b.touches||[]).length-(a.touches||[]).length;
 case "touches_asc":return(a.touches||[]).length-(b.touches||[]).length;
 case "followUp_asc":return new Date(a.nextFollowUp||"9999")-new Date(b.nextFollowUp||"9999");
 case "followUp_desc":return new Date(b.nextFollowUp||"0")-new Date(a.nextFollowUp||"0");
 default:return 0;
 }
 });

 return list;
}

// APPLY FILTERS TO LEADS 
function applyLeadFilters(leads,filters,search){
 const now=new Date();
 const today=new Date();today.setHours(0,0,0,0);
 const dAgo=days=>new Date(now.getTime()-days*24*60*60*1000);
 let list=[...leads];

 if(search)list=list.filter(l=>(l.company+l.contact+l.email).toLowerCase().includes(search.toLowerCase()));
 if(filters.owner)list=list.filter(l=>l.owner===filters.owner);
 if(filters.status)list=list.filter(l=>l.status===filters.status);
 if(filters.hasEmail==="yes")list=list.filter(l=>l.email&&l.email.trim());
 if(filters.hasEmail==="no")list=list.filter(l=>!l.email||!l.email.trim());
 if(filters.hasLinkedIn==="yes")list=list.filter(l=>l.linkedin&&l.linkedin.trim());
 if(filters.hasLinkedIn==="no")list=list.filter(l=>!l.linkedin||!l.linkedin.trim());
 if(filters.hasSecondary==="yes")list=list.filter(l=>(l.secondaryContacts||[]).length>0);
 if(filters.hasSecondary==="no")list=list.filter(l=>(l.secondaryContacts||[]).length===0);
 if(filters.lastActivityRange==="14+")list=list.filter(l=>new Date(l.lastActivity)<dAgo(14));
 if(filters.lastActivityRange==="30+")list=list.filter(l=>new Date(l.lastActivity)<dAgo(30));
 if(filters.lastActivityRange==="60+")list=list.filter(l=>new Date(l.lastActivity)<dAgo(60));
 if(filters.lastActivityRange==="week")list=list.filter(l=>new Date(l.lastActivity)>=dAgo(7));
 if(filters.lastActivityRange==="month")list=list.filter(l=>new Date(l.lastActivity)>=dAgo(30));
 if(filters.addedRange==="week")list=list.filter(l=>new Date(l.createdAt)>=dAgo(7));
 if(filters.addedRange==="month")list=list.filter(l=>new Date(l.createdAt)>=dAgo(30));
 if(filters.addedRange==="30")list=list.filter(l=>new Date(l.createdAt)>=dAgo(30));
 if(filters.addedRange==="90")list=list.filter(l=>new Date(l.createdAt)>=dAgo(90));

 list.sort((a,b)=>{
 switch(filters.sort){
 case "company_asc":return(a.company||"").localeCompare(b.company||"");
 case "company_desc":return(b.company||"").localeCompare(a.company||"");
 case "contact_asc":return(a.contact||"").localeCompare(b.contact||"");
 case "contact_desc":return(b.contact||"").localeCompare(a.contact||"");
 case "lastActivity_desc":return new Date(b.lastActivity||0)-new Date(a.lastActivity||0);
 case "lastActivity_asc":return new Date(a.lastActivity||0)-new Date(b.lastActivity||0);
 case "createdAt_desc":return new Date(b.createdAt||0)-new Date(a.createdAt||0);
 case "createdAt_asc":return new Date(a.createdAt||0)-new Date(b.createdAt||0);
 default:return 0;
 }
 });

 return list;
}

// GLOBAL SEARCH 
function GlobalSearch({prospects,leads,deals,stages,onNavigate,onOpenDeal,onOpenLead,onClose}){
 const [q,setQ]=useState("");
 const [focused,setFocused]=useState(true);
 const inputRef=useRef(null);

 useEffect(()=>{if(inputRef.current)inputRef.current.focus();},[]);

 const lq=q.toLowerCase().trim();
 const results=lq.length<2?[]:([
 ...deals.map(d=>({type:"Deal",label:d.company,sub:(stages.find(s=>s.id===d.stageId)?.name||"")+(d.arr?" · $"+Number(d.arr).toLocaleString():""),id:d.id,data:d,icon:"",color:"#1E3A5F"})),
 ...leads.map(l=>({type:"Lead",label:l.company,sub:l.contact+(l.status?" · "+l.status:""),id:l.id,data:l,icon:"",color:"#701427"})),
 ...prospects.map(p=>({type:"Prospect",label:p.company,sub:((p.contacts||[])[0]?.name||p.contact)+(p.status?" · "+p.status:""),id:p.id,data:p,icon:"",color:"#5B3A8A"})),
 ...deals.filter(d=>d.contact).map(d=>({type:"Contact",label:d.contact,sub:d.company+" · Deal",id:"c-"+d.id,data:d,icon:"",color:"#7C4D00"})),
 ...leads.filter(l=>l.contact).map(l=>({type:"Contact",label:l.contact,sub:l.company+" · Lead",id:"cl-"+l.id,data:l,icon:"",color:"#7C4D00"})),
 ...prospects.flatMap(p=>(p.contacts||[{name:p.contact}]).filter(c=>c.name).map(c=>({type:"Contact",label:c.name,sub:p.company+" · Prospect",id:"cp-"+p.id+"-"+c.name,data:p,icon:"",color:"#7C4D00"}))),
 ].filter(r=>r.label?.toLowerCase().includes(lq)||r.sub?.toLowerCase().includes(lq)).slice(0,12));

 const handleClick=(r)=>{
 if(r.type==="Deal")onOpenDeal(r.data);
 else if(r.type==="Lead")onOpenLead(r.data);
 else if(r.type==="Prospect"||r.type==="Contact")onNavigate(r.type==="Prospect"?"prospects":r.data.stage_id?"board":"leads");
 onClose();
 };

 return(
 <div style={{position:"fixed",inset:0,background:"rgba(30,58,95,0.4)",backdropFilter:"blur(6px)",zIndex:4000,display:"flex",alignItems:"flex-start",justifyContent:"center",paddingTop:80,padding:"80px 20px 20px"}} onClick={onClose}>
 <div style={{background:"#fff",borderRadius:16,width:"100%",maxWidth:580,boxShadow:"0 32px 100px rgba(30,58,95,0.3)",overflow:"hidden"}} onClick={e=>e.stopPropagation()}>
 <div style={{display:"flex",alignItems:"center",gap:12,padding:"14px 18px",borderBottom:"1px solid #F0F0F0"}}>
 <span style={{fontSize:18,flexShrink:0}}></span>
 <input
 ref={inputRef}
 value={q}
 onChange={e=>setQ(e.target.value)}
 onKeyDown={e=>e.key==="Escape"&&onClose()}
 placeholder="Search prospects, leads, deals, contacts…"
 style={{flex:1,border:"none",outline:"none",fontSize:16,color:"#0F1E2E",fontFamily:"inherit",background:"transparent"}}
 />
 {q&&<button onClick={()=>setQ("")} style={{background:"none",border:"none",color:"#D6D3D1",cursor:"pointer",fontSize:18,lineHeight:1,padding:0}}></button>}
 <kbd style={{background:"#F5F5F5",border:"1px solid #D6D3D1",borderRadius:5,padding:"2px 7px",fontSize:11,color:"#94A3B8",flexShrink:0}}>esc</kbd>
 </div>
 {q.length>=2&&results.length===0&&(
 <div style={{padding:"32px 20px",textAlign:"center",color:"#94A3B8",fontSize:14}}>No results for "<strong>{q}</strong>"</div>
 )}
 {q.length<2&&(
 <div style={{padding:"20px 18px",color:"#94A3B8",fontSize:13}}>
 <div style={{fontWeight:700,marginBottom:10,fontSize:11,textTransform:"uppercase",letterSpacing:"0.07em"}}>Search across</div>
 <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
 {[{icon:"",label:"Deals"},{icon:"",label:"Leads"},{icon:"",label:"Prospects"},{icon:"",label:"Contacts"}].map(t=>(
 <span key={t.label} style={{background:"#F5F5F5",borderRadius:20,padding:"4px 12px",fontSize:12,fontWeight:600}}>{t.icon} {t.label}</span>
 ))}
 </div>
 </div>
 )}
 {results.length>0&&(
 <div style={{maxHeight:400,overflowY:"auto"}}>
 {["Deal","Lead","Prospect","Contact"].map(type=>{
 const group=results.filter(r=>r.type===type);
 if(!group.length)return null;
 return(
 <div key={type}>
 <div style={{padding:"8px 18px 4px",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.08em",color:"#94A3B8",background:"#F5F2EE",borderBottom:"1px solid #F5F5F5"}}>{type}s</div>
 {group.map(r=>(
 <div key={r.id} onClick={()=>handleClick(r)}
 style={{display:"flex",alignItems:"center",gap:12,padding:"11px 18px",cursor:"pointer",borderBottom:"1px solid #F9F9F9",transition:"background 0.1s"}}
 onMouseEnter={e=>e.currentTarget.style.background="#F5F7FF"}
 onMouseLeave={e=>e.currentTarget.style.background=""}>
 <div style={{width:32,height:32,borderRadius:8,background:r.color+"15",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,flexShrink:0}}>{r.icon}</div>
 <div style={{flex:1,minWidth:0}}>
 <div style={{fontWeight:600,color:"#0F1E2E",fontSize:13,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.label}</div>
 <div style={{color:"#94A3B8",fontSize:11,marginTop:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.sub}</div>
 </div>
 <span style={{fontSize:10,background:r.color+"15",color:r.color,borderRadius:4,padding:"2px 7px",fontWeight:700,flexShrink:0}}>{r.type}</span>
 </div>
 ))}
 </div>
 );
 })}
 </div>
 )}
 <div style={{padding:"8px 18px",borderTop:"1px solid #F5F5F5",display:"flex",gap:12,fontSize:11,color:"#94A3B8"}}>
 <span>↵ select</span><span>esc close</span>
 </div>
 </div>
 </div>
 );
}

